func sortedUnique(in []string) []string {
	m := map[string]struct{}{}
	for _, s := range in {
		m[s] = struct{}{}
	}
	out := make([]string, 0, len(m))
	for k := range m {
		out = append(out, k)
	}
	for i := 0; i < len(out); i++ {
		for j := i + 1; j < len(out); j++ {
			if out[j] < out[i] {
				out[i], out[j] = out[j], out[i]
			}
		}
	}
	return out
}

func (s *Server) handleChat(ctx context.Context, p *Player, text string) {
	if cmd, ok := parseCommand(text); ok {
		spec, ok := commandSpecs()[cmd.Name]
		if !ok {
			s.systemTo(p, "Unknown command. Try /help")
			return
		}
		if p.Role < spec.MinRole {
			s.systemTo(p, "You do not have permission to use that command.")
			return
		}
		if err := spec.Handle(ctx, s, p, cmd); err != nil {
			if errors.Is(err, ErrForbidden) {
				s.systemTo(p, "Forbidden.")
				return
			}
			s.systemTo(p, "Command error.")
			return
		}
		return
	}
	s.broadcast("chat", ChatOut{From: p.Name, Text: text})
}

func (s *Server) serveConn(ctx context.Context, conn net.Conn, role Role, name string) {
	defer conn.Close()

	remote := conn.RemoteAddr().String()
	if be, ok := s.isBanned(remote); ok {
		w := bufio.NewWriter(conn)
		msg := "banned"
		if be.Reason != "" {
			msg += ": " + be.Reason
		}
		if !be.Until.IsZero() {
			msg += " until " + be.Until.UTC().Format(time.RFC3339)
		}
		_ = writeJSONLine(w, Envelope{Type: "kick", Data: mustJSON(KickOut{Reason: msg})})
		return
	}

	id := s.nextPlayerID()
	if name == "" {
		name = id
	}
	name = sanitizeName(name)

	p := &Player{
		ID:        id,
		Name:      name,
		Conn:      conn,
		Remote:    remote,
		Role:      role,
		Connected: time.Now(),
		Send:      make(chan []byte, 128),
	}

	s.addPlayer(p)
	defer s.removePlayer(p.ID)

	go func() {
		for {
			select {
			case <-ctx.Done():
				return
			case b, ok := <-p.Send:
				if !ok {
					return
				}
				_ = conn.SetWriteDeadline(time.Now().Add(10 * time.Second))
				_, err := conn.Write(b)
				if err != nil {
					return
				}
			}
		}
	}()

	sendEnvelope(p, "login", LoginOut{ID: p.ID, Name: p.Name, Role: p.Role.String()})
	s.systemBroadcast(fmt.Sprintf("%s joined. (%s)", p.Name, p.Role.String()))

	sc := bufio.NewScanner(conn)
	sc.Buffer(make([]byte, 1024), 1024*1024)
	for sc.Scan() {
		line := strings.TrimSpace(sc.Text())
		if line == "" {
			continue
		}
		var env Envelope
		if err := json.Unmarshal([]byte(line), &env); err != nil {
			continue
		}
		switch strings.ToLower(env.Type) {
		case "chat":
			var in ChatIn
			if err := json.Unmarshal(env.Data, &in); err != nil {
				continue
			}
			s.handleChat(ctx, p, in.Text)
		case "login":
			var in LoginIn
			if err := json.Unmarshal(env.Data, &in); err != nil {
				continue
			}
			n := sanitizeName(in.Name)
			if n == "" {
				continue
			}
			s.mu.Lock()
			delete(s.nameIdx, strings.ToLower(p.Name))
			p.Name = n
			s.nameIdx[strings.ToLower(p.Name)] = p.ID
			s.mu.Unlock()
			sendEnvelope(p, "login", LoginOut{ID: p.ID, Name: p.Name, Role: p.Role.String()})
		default:
		}
	}
	s.systemBroadcast(fmt.Sprintf("%s left.", p.Name))
}

func sanitizeName(s string) string {
	s = strings.TrimSpace(s)
	if s == "" {
		return ""
	}
	if len(s) > 24 {
		s = s[:24]
	}
	out := make([]rune, 0, len(s))
	for _, r := range s {
		if r >= 32 && r < 127 && r != '"' && r != '\\' {
			out = append(out, r)
		}
	}
	return strings.TrimSpace(string(out))
}

func mustJSON(v any) json.RawMessage {
	b, _ := json.Marshal(v)
	return b
}

type HeaderConn struct {
	net.Conn
	br *bufio.Reader
}

func (hc *HeaderConn) Read(p []byte) (int, error) {
	return hc.br.Read(p)
}

func readHeaderLine(br *bufio.Reader, deadline time.Duration) (string, error) {
	_ = br.Peek(0)
	type dl interface{ SetReadDeadline(time.Time) error }
	if c, ok := br.(*bufio.Reader); ok {
		_ = c
	}
	return br.ReadString('\n')
}

func acceptWithHeaders(ln net.Listener) (net.Conn, Role, string, error) {
	conn, err := ln.Accept()
	if err != nil {
		return nil, RolePlayer, "", err
	}
	_ = conn.SetReadDeadline(time.Now().Add(5 * time.Second))
	br := bufio.NewReader(conn)
	line, err := br.ReadString('\n')
	if err != nil {
		conn.Close()
		return nil, RolePlayer, "", err
	}
	_ = conn.SetReadDeadline(time.Time{})
	line = strings.TrimSpace(line)
	role := RolePlayer
	name := ""
	if strings.HasPrefix(strings.ToUpper(line), "HEADERS ") {
		h := strings.TrimSpace(line[len("HEADERS "):])
		parts := strings.Split(h, ";")
		for _, part := range parts {
			part = strings.TrimSpace(part)
			if part == "" {
				continue
			}
			kv := strings.SplitN(part, "=", 2)
			if len(kv) != 2 {
				continue
			}
			k := strings.ToLower(strings.TrimSpace(kv[0]))
			v := strings.TrimSpace(kv[1])
			switch k {
			case "role":
				role = parseRole(v)
			case "name":
				name = v
			}
		}
	} else {
		br = bufio.NewReader(ioMultiString(line+"\n", conn))
	}
	hc := &HeaderConn{Conn: conn, br: br}
	return hc, role, name, nil
}

type multiString struct {
	s   *strings.Reader
	rem net.Conn
}

func ioMultiString(prefix string, conn net.Conn) *multiString {
	return &multiString{s: strings.NewReader(prefix), rem: conn}
}

func (m *multiString) Read(p []byte) (int, error) {
	if m.s != nil && m.s.Len() > 0 {
		return m.s.Read(p)
	}
	m.s = nil
	return m.rem.Read(p)
}

func (m *multiString) Close() error { return m.rem.Close() }

func (m *multiString) Write(p []byte) (int, error) { return m.rem.Write(p) }

func (m *multiString) LocalAddr() net.Addr { return m.rem.LocalAddr() }

func (m *multiString) RemoteAddr() net.Addr { return m.rem.RemoteAddr() }

func (m *multiString) SetDeadline(t time.Time) error { return m.rem.SetDeadline(t) }

func (m *multiString) SetReadDeadline(t time.Time) error { return m.rem.SetReadDeadline(t) }

func (m *multiString) SetWriteDeadline(t time.Time) error { return m.rem.SetWriteDeadline(t) }

func (s *Server) Serve(ctx context.Context, addr string) error {
	ln, err := net.Listen("tcp", addr)
	if err != nil {
		return err
	}
	s.listener = ln
	s.logger.Printf("game server listening on %s", addr)

	defer ln.Close()

	for {
		select {
		case <-ctx.Done():
			return nil
		default:
		}
		conn, role, name, err := acceptWithHeaders(ln)
		if err != nil {
			if errors.Is(err, net.ErrClosed) {
				return nil
			}
			continue
		}

		if role == RoleAdmin {
			if subtle.ConstantTimeCompare([]byte(os.Getenv("ALLOW_ADMIN_FROM_CLIENT_HEADERS")), []byte("1")) != 1 {
				role = RolePlayer
			}
		}

		go s.serveConn(ctx, conn, role, name)
	}
}

func (s *Server) ServeHTTP(addr string) error {
	mux := http.NewServeMux()
	mux.HandleFunc("/health", func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(200)
		_, _ = w.Write([]byte("ok"))
	})
	mux.HandleFunc("/players", func(w http.ResponseWriter, r *http.Request) {
		type outP struct {
			ID     string `json:"id"`
			Name   string `json:"name"`
			Role   string `json:"role"`
			Remote string `json:"remote"`
		}
		ps := s.listPlayers()
		out := make([]outP, 0, len(ps))
		for _, p := range ps {
			out = append(out, outP{ID: p.ID, Name: p.Name, Role: p.Role.String(), Remote: p.Remote})
		}
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(out)
	})
	srv := &http.Server{Addr: addr, Handler: mux}
	s.logger.Printf("http admin/status listening on %s", addr)
	return srv.ListenAndServe()
}

func main() {
	logger := log.New(os.Stdout, "", log.LstdFlags|log.Lmicroseconds)
	gameAddr := getenv("GAME_ADDR", ":7777")
	httpAddr := getenv("HTTP_ADDR", ":8080")

	s := NewServer(logger)

	ctx, cancel := signal.NotifyContext(context.Background(), os.Interrupt, syscall.SIGTERM)
	defer cancel()

	go func() {
		if err := s.ServeHTTP(httpAddr); err != nil && !errors.Is(err, http.ErrServerClosed) {
			logger.Printf("http error: %v", err)
			cancel()
		}
	}()

	if err := s.Serve(ctx, gameAddr); err != nil {
		logger.Printf("server error: %v", err)
	}
}

func getenv(k, def string) string {
	v := os.Getenv(k)
	if v == "" {
		return def
	}
	return v
}